import { BrowserRouter, Routes, Route } from "react-router-dom";

function Dashboard(){
  return <div className="p-6 text-xl">Dashboard Working ✅</div>;
}

export default function App(){
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/" element={<Dashboard />} />
      </Routes>
    </BrowserRouter>
  )
}
